python3 << 'EOF'
import json
import sys

files = [
    "hobber-redwyne.edges.jsonl",
    "horas-redwyne.edges.jsonl",
    "manfryd-redwyne.edges.jsonl",
    "olenna-tyrell.edges.jsonl",
    "patricia-redwyne.edges.jsonl",
]

# Required fields per decision type
emit_edge_required = {'decision', 'candidate_kind', 'evidence_kind', 'source_slug', 'target_slug', 'edge_type', 'evidence_snippet', 'evidence_section', 'confidence_tier'}
reject_required = {'decision', 'candidate_kind', 'source_slug', 'target_slug', 'reason'}

errors = []

for filepath in files:
    with open(filepath) as f:
        for line_num, line in enumerate(f, 1):
            row = json.loads(line)
            decision = row.get('decision')

            if decision == 'emit_edge':
                missing = emit_edge_required - set(row.keys())
                if missing:
                    errors.append(f"{filepath}:{line_num} emit_edge missing: {missing}")
                # Check field types
                if not isinstance(row.get('confidence_tier'), int):
                    errors.append(f"{filepath}:{line_num} confidence_tier is not int")
            elif decision == 'reject_just_mention':
                missing = reject_required - set(row.keys())
                if missing:
                    errors.append(f"{filepath}:{line_num} reject missing: {missing}")
            else:
                errors.append(f"{filepath}:{line_num} unknown decision: {decision}")

if errors:
    for e in errors[:20]:
        print(e)
    if len(errors) > 20:
        print(f"... and {len(errors)-20} more errors")
else:
    print("✓ All 263 rows have valid schema")
    # Print summary
    for filepath in files:
        with open(filepath) as f:
            rows = [json.loads(line) for line in f]
            emit = sum(1 for r in rows if r['decision'] == 'emit_edge')
            reject = sum(1 for r in rows if r['decision'] == 'reject_just_mention')
            print(f"  {filepath}: {emit} emit_edge, {reject} reject_just_mention")

EOF
